 81	// stablePreDispatchImplementationDirtyPaths re-reads the project dirt and only
 82	// treats implementation paths as actionable when they survive the immediate
 83	// recheck. This filters transient rename/delete paths that can briefly appear
 84	// in watch mode right after a successful land.
 85	func stablePreDispatchImplementationDirtyPaths(projectRoot string, dirtyPaths []string) ([]string, []string, error) {
 86		normalized := normalizePreDispatchDirtyPaths(dirtyPaths)
 87		if projectRoot == "" || len(normalized) == 0 {
 88			return normalized, normalized, nil
 89		}
 90	
 91		currentPaths, err := preDispatchDirtyPathLister(projectRoot)
 92		if err != nil {
 93			return nil, nil, fmt.Errorf("rechecking pre-dispatch dirt: %w", err)
 94		}
 95		return intersectPreDispatchDirtyPaths(currentPaths, normalized), currentPaths, nil
 96	}
