117	func preservePreDispatchDirtyPaths(projectRoot string, dirtyPaths []string) (*PreDispatchDirtyPreservation, error) {
118		if projectRoot == "" {
119			return nil, fmt.Errorf("project root is required for pre-dispatch dirty preservation")
120		}
121		normalized := normalizePreDispatchDirtyPaths(dirtyPaths)
122		if len(normalized) == 0 {
123			return nil, fmt.Errorf("no dirty implementation paths to preserve")
124		}
125	
126		var preserved *PreDispatchDirtyPreservation
127		if err := withTrackerLock(projectRoot, "preserve_dirt", func() error {
128			var err error
129			preserved, err = preservePreDispatchDirtyPathsLocked(projectRoot, normalized)
130			return err
131		}); err != nil {
132			return nil, err
133		}
134		return preserved, nil
135	}
136	
137	func preservePreDispatchDirtyPathsLocked(projectRoot string, dirtyPaths []string) (*PreDispatchDirtyPreservation, error) {
138		if err := internalgit.Command(context.Background(), projectRoot, "rev-parse", "--is-inside-work-tree").Run(); err != nil {
139			return nil, fmt.Errorf("verifying project worktree for pre-dispatch preservation: %w", err)
140		}
141		if out, err := internalgit.Command(context.Background(), projectRoot, "rev-parse", "--verify", "HEAD").CombinedOutput(); err != nil {
142			return nil, fmt.Errorf("resolving HEAD for pre-dispatch preservation: %s: %w", strings.TrimSpace(string(out)), err)
143		}
144	
145		stashBefore, _ := resolveOptionalGitRef(projectRoot, "refs/stash")
146		preserveID := GenerateAttemptID()
147		preserveRef := preDispatchDirtyPreserveRefPrefix + preserveID
148		stashMsg := "ddx pre-dispatch preserve " + preserveID
149		stashArgs := []string{"stash", "push", "--include-untracked", "--message", stashMsg, "--"}
150		stashArgs = append(stashArgs, dirtyPaths...)
151		if out, err := internalgit.Command(context.Background(), projectRoot, stashArgs...).CombinedOutput(); err != nil {
152			return nil, fmt.Errorf("preserving pre-dispatch dirty implementation paths: %s: %w", strings.TrimSpace(string(out)), err)
153		}
154	
155		stashAfter, ok := resolveOptionalGitRef(projectRoot, "refs/stash")
156		if !ok || stashAfter == "" || stashAfter == stashBefore {
157			return nil, fmt.Errorf("preserving pre-dispatch dirty implementation paths did not create a recoverable stash entry")
158		}
159		if out, err := internalgit.Command(context.Background(), projectRoot, "update-ref", preserveRef, stashAfter).CombinedOutput(); err != nil {
160			return nil, fmt.Errorf("pinning pre-dispatch dirty preservation ref: %s: %w", strings.TrimSpace(string(out)), err)
161		}
162		_, _ = internalgit.Command(context.Background(), projectRoot, "stash", "drop", "stash@{0}").CombinedOutput()
163	
164		remainingPaths, err := preDispatchDirtyPathLister(projectRoot)
165		if err != nil {
166			return nil, fmt.Errorf("verifying preserved pre-dispatch dirt: %w", err)
167		}
168		if overlap := intersectPreDispatchDirtyPaths(remainingPaths, dirtyPaths); len(overlap) > 0 {
169			return nil, fmt.Errorf("preserving pre-dispatch dirty implementation paths left the project worktree dirty: %s", strings.Join(overlap, ", "))
170		}
171	
172		return &PreDispatchDirtyPreservation{
173			DirtyPaths:     append([]string(nil), dirtyPaths...),
174			PreserveRef:    preserveRef,
175			RecoverCommand: preDispatchDirtyRecoverCommand(preserveRef),
176		}, nil
177	}
178	
179	func checkpointPreDispatchDirt(projectRoot, attemptID string) (bool, error) {
180		if err := internalgit.Command(context.Background(), projectRoot, "rev-parse", "--is-inside-work-tree").Run(); err != nil {
181			return false, nil
182		}
183		headOut, err := internalgit.Command(context.Background(), projectRoot, "rev-parse", "--verify", "HEAD").Output()
184		if err != nil {
185			return false, nil
186		}
187		head := strings.TrimSpace(string(headOut))
188		if head == "" {
189			return false, nil
190		}
191	
192		skipWorktreePaths, err := checkpointSkipWorktreePaths(projectRoot)
193		if err != nil {
194			return false, err
195		}
196	
197		dirtyPaths, err := preDispatchDirtyPathLister(projectRoot)
198		if err != nil {
199			return false, err
200		}
201		if len(dirtyPaths) == 0 {
202			return false, nil
203		}
204	
205		allowedPaths, blockedPaths := classifyPreDispatchDirtyPaths(dirtyPaths)
206		if len(blockedPaths) > 0 {
207			stableBlockedPaths, currentDirtyPaths, err := stablePreDispatchImplementationDirtyPaths(projectRoot, blockedPaths)
208			if err != nil {
209				return false, err
210			}
211			if len(stableBlockedPaths) > 0 {
212				return false, fmt.Errorf(
213					"%s%s; commit or clean those files before rerunning so the bead's [ddx-<id>] substantive commit stays intentional",
214					preDispatchCheckpointDirtyRefusalPrefix,
215					strings.Join(stableBlockedPaths, ", "),
216				)
217			}
218			allowedPaths, _ = classifyPreDispatchDirtyPaths(currentDirtyPaths)
219		}
220		if len(allowedPaths) == 0 {
221			return false, nil
222		}
223	
224		indexFile, err := config.CreateExecutionScratch(projectRoot, "ddx-pre-dispatch-index-*")
225		if err != nil {
226			return false, fmt.Errorf("creating temp checkpoint index: %w", err)
227		}
228		indexPath := indexFile.Name()
229		_ = indexFile.Close()
230		_ = os.Remove(indexPath)
231		defer func() { _ = os.Remove(indexPath) }()
232	
233		gitWithIndex := func(args ...string) ([]byte, error) {
234			cmd := internalgit.Command(context.Background(), projectRoot, args...)
235			cmd.Env = append(cmd.Env, "GIT_INDEX_FILE="+indexPath)
236			return cmd.CombinedOutput()
237		}
238	
239		if out, err := gitWithIndex("read-tree", "HEAD"); err != nil {
240			return false, fmt.Errorf("initializing checkpoint index: %s: %w", strings.TrimSpace(string(out)), err)
241		}
242	
243		addArgs := []string{"add", "-A", "--force", "--"}
244		addArgs = append(addArgs, allowedPaths...)
245		if out, err := gitWithIndex(addArgs...); err != nil {
246			return false, fmt.Errorf("staging checkpoint changes: %s: %w", strings.TrimSpace(string(out)), err)
247		}
248	
249		changedOut, err := gitWithIndex("diff", "--cached", "--name-only")
250		if err != nil {
251			return false, fmt.Errorf("checking checkpoint diff: %w", err)
252		}
253		if len(bytes.TrimSpace(changedOut)) == 0 {
254			return false, nil
255		}
256	
257		treeOut, err := gitWithIndex("write-tree")
258		if err != nil {
259			return false, fmt.Errorf("writing checkpoint tree: %s: %w", strings.TrimSpace(string(treeOut)), err)
260		}

