 84	func dirtyWorktreePaths(dir string) []string {
 85		out, err := internalgit.Command(context.Background(), dir, "status", "--porcelain", "--untracked-files=all").Output()
 86		if err != nil {
 87			return nil
 88		}
 89		var paths []string
 90		seen := map[string]bool{}
 91		for _, line := range strings.Split(string(out), "\n") {
 92			line = strings.TrimRight(line, "\r")
 93			if strings.TrimSpace(line) == "" || len(line) < 4 {
 94				continue
 95			}
 96			path := strings.TrimSpace(line[3:])
 97			if idx := strings.Index(path, " -> "); idx >= 0 {
 98				path = strings.TrimSpace(path[idx+4:])
 99			}
100			if path == "" || seen[path] {
101				continue
102			}
103			seen[path] = true
104			paths = append(paths, path)
105		}
106		return paths
107	}
