109	// EvidenceLandExcludePathspecs returns git pathspec-exclusion fragments
110	// applied when landEvidence / VerifyCleanWorktree stage the evidence
111	// directory. Only excludes the multi-thousand-line embedded session log
112	// (the single file that actually explodes past provider context
113	// limits). prompt.md, usage.json, manifest.json, and result.json remain
114	// tracked — they are small and serve the audit-trail contract. The
115	// gitignore written by `ddx init` already treats .ddx/executions/*/
116	// embedded as ignored; this pathspec is defence-in-depth for force-add
117	// paths.
118	//
119	// Regression anchor: ddx-39e27896 — session logs landed as tracked
120	// evidence caused retry prompts to balloon past 2M+ tokens and crash
121	// every provider with n_keep > n_ctx.
122	func EvidenceLandExcludePathspecs() []string {
123		return []string{
124			":(exclude,glob).ddx/executions/*/embedded/**",
125		}
126	}
