128	// EvidenceReviewExcludePathspecs returns git pathspec-exclusion fragments
129	// applied when review-prompt synthesis runs `git show <rev>` over the
130	// evidence commit. Broader than EvidenceLandExcludePathspecs: excludes
131	// prompt.md and usage.json too, because even though they're tracked for
132	// audit, they're execution-artifact noise from the reviewer's
133	// perspective — the reviewer wants to see the implementation diff, not
134	// the prior attempt's prompt or token counters. This also protects
135	// against old commits (pre-fix) that committed the session log
136	// directly.
137	//
138	// Regression anchor: ddx-39e27896.
139	func EvidenceReviewExcludePathspecs() []string {
140		return []string{
141			":(exclude,glob).ddx/executions/*/embedded/**",
142			":(exclude,glob).ddx/executions/*/prompt.md",
143			":(exclude,glob).ddx/executions/*/usage.json",
144		}
145	}
