147	// SynthesizeCommit stages real file changes, explicitly excluding harness noise
148	// paths, and creates a commit with msg as the commit message. Returns (true, nil)
149	// when a commit was made, (false, nil) when nothing real remained to commit
150	// after exclusions, and (false, err) on failure.
151	func (r *RealGitOps) SynthesizeCommit(dir, msg string) (bool, error) {
152		// Do NOT list already-gitignored paths (.ddx/agent-logs, .ddx/workers) as
153		// :(exclude) pathspecs. Git treats a path named by :(exclude) as explicitly
154		// referenced, so when the path is also .gitignored git emits "The following
155		// paths are ignored by one of your .gitignore files" AND exits 1 — even
156		// though the pathspec is trying to SKIP it. Paths already in .gitignore are
157		// excluded by default; excludes here are only for paths that would
158		// otherwise be tracked.
159		addArgs := []string{
160			"add", "-A", "--",
161			".",
162		}
163		addArgs = append(addArgs, synthesizeCommitExcludePathspecs(dir)...)
164		if err := internalgit.Command(context.Background(), dir, addArgs...).Run(); err != nil {
165			return false, fmt.Errorf("staging changes: %w", err)
166		}
167		statusOut, _ := internalgit.Command(context.Background(), dir, "diff", "--cached", "--name-only").Output()
168		if len(bytes.TrimSpace(statusOut)) == 0 {
169			return false, nil
170		}
171		if msg == "" {
172			msg = "chore: execute-bead synthesized result commit"
173		}
174		out, err := internalgit.Command(context.Background(), dir, "commit", "-m", msg).CombinedOutput()
175		if err != nil {
176			return false, fmt.Errorf("synthesize commit: %s: %w", strings.TrimSpace(string(out)), err)
177		}
178		return true, nil
179	}
180	
181	func synthesizeCommitExcludePathspecs(dir string) []string {
182		candidates := []struct {
